import React, { useEffect, useState } from "react";
import { api } from "../api";

export default function Dashboard({ onError }) {
  const [items, setItems] = useState([]);
  const [name, setName] = useState("");
  const [category, setCategory] = useState("Other");
  const [quantity, setQuantity] = useState(1);
  const [unit, setUnit] = useState("pcs");
  const [price, setPrice] = useState(0);
  const [expiry_date, setExpiry] = useState("");

  const [voiceText, setVoiceText] = useState("");
  const [barcode, setBarcode] = useState("");
  const [ocrFile, setOcrFile] = useState(null);
  const [ocrItems, setOcrItems] = useState([]);

  const quickItems = [
    {
      name: "Tomato",
      category: "Vegetables",
      unit: "pcs",
      image: "https://cdn-icons-png.flaticon.com/512/2909/2909899.png",
    },
    {
      name: "Carrot",
      category: "Vegetables",
      unit: "pcs",
      image: "https://cdn-icons-png.flaticon.com/512/2224/2224301.png",
    },
    {
      name: "Broccoli",
      category: "Vegetables",
      unit: "pcs",
      image: "https://cdn-icons-png.flaticon.com/512/2346/2346958.png",
    },
    {
      name: "Onion",
      category: "Vegetables",
      unit: "pcs",
      image: "https://cdn-icons-png.flaticon.com/512/765/765544.png",
    },
    {
      name: "Milk",
      category: "Dairy",
      unit: "L",
      image: "https://cdn-icons-png.flaticon.com/512/2674/2674505.png",
    },
    {
      name: "Apple",
      category: "Fruits",
      unit: "pcs",
      image: "https://cdn-icons-png.flaticon.com/512/415/415733.png",
    },
  ];

  async function load() {
    try {
      const data = await api.listInventory();
      setItems(data);
      onError("");
    } catch (e) {
      onError(e.message);
    }
  }

  useEffect(() => {
    load();
  }, []);

  async function addManual() {
    try {
      await api.addItem({
        name,
        category,
        quantity: Number(quantity),
        unit,
        price: Number(price),
        expiry_date: expiry_date ? expiry_date : null,
      });

      setName("");
      setCategory("Other");
      setQuantity(1);
      setUnit("pcs");
      setPrice(0);
      setExpiry("");
      onError("");
      load();
    } catch (e) {
      onError(e.message);
    }
  }

  async function del(id) {
    try {
      await api.deleteItem(id);
      onError("");
      load();
    } catch (e) {
      onError(e.message);
    }
  }

  async function doQuickAdd() {
    try {
      await api.quickAdd({ text: voiceText });
      setVoiceText("");
      onError("");
      load();
    } catch (e) {
      onError(e.message);
    }
  }

  async function doBarcodeLookup() {
    try {
      const info = await api.barcodeLookup({ barcode });
      setName(info.name || "");
      setCategory(info.category || "Other");
      setExpiry(info.estimated_expiry_date || "");
      onError("");
    } catch (e) {
      onError(e.message);
    }
  }

  async function doOCR() {
    try {
      if (!ocrFile) return;
      const res = await api.ocrReceipt(ocrFile);
      setOcrItems(res.items || []);
      onError("");
    } catch (e) {
      onError(e.message);
    }
  }

  async function commitOCR() {
    try {
      if (!ocrItems.length) return;
      await api.ocrCommit(ocrItems);
      setOcrItems([]);
      setOcrFile(null);
      onError("");
      load();
    } catch (e) {
      onError(e.message);
    }
  }

  const totalItems = items.length;
  const atRiskItems = items.filter((it) => it.at_risk).length;
  const noExpiryItems = items.filter((it) => !it.expiry_date).length;

  return (
    <div className="dashboardPage">
      <div className="heroCard">
        <div>
          <h1 className="heroTitle">Smart Pantry Dashboard</h1>
          <p className="heroSubtitle">
            Manage groceries, reduce food waste, and get AI-powered recipe ideas.
          </p>
        </div>

        <div className="heroStats">
          <div className="statCard">
            <span className="statLabel">Total Items</span>
            <span className="statValue">{totalItems}</span>
          </div>
          <div className="statCard warningCard">
            <span className="statLabel">At-Risk</span>
            <span className="statValue">{atRiskItems}</span>
          </div>
          <div className="statCard neutralCard">
            <span className="statLabel">No Expiry</span>
            <span className="statValue">{noExpiryItems}</span>
          </div>
        </div>
      </div>

      <div className="dashboardGrid">
        <div className="panelCard">
          <h2>Add Item Manually</h2>
          <p className="panelHint">
            Choose a common item below or enter details manually.
          </p>

          <div className="quickGrid">
            {quickItems.map((item, idx) => (
              <div
                key={idx}
                className="quickItemCard"
                onClick={() => {
                  setName(item.name);
                  setCategory(item.category);
                  setUnit(item.unit);
                }}
              >
                <img src={item.image} alt={item.name} className="quickItemImage" />
                <div className="quickItemName">{item.name}</div>
                <div className="quickItemCategory">{item.category}</div>
              </div>
            ))}
          </div>

          {name && (
            <div className="selectedItemBox">
              Selected: <b>{name}</b> <span className="badge">{category}</span>
            </div>
          )}

          <div className="formGrid twoCols">
            <div>
              <label>Name</label>
              <input value={name} onChange={(e) => setName(e.target.value)} />
            </div>
            <div>
              <label>Category</label>
              <input value={category} onChange={(e) => setCategory(e.target.value)} />
            </div>
          </div>

          <div className="formGrid fourCols">
            <div>
              <label>Quantity</label>
              <input
                type="number"
                value={quantity}
                onChange={(e) => setQuantity(e.target.value)}
              />
            </div>
            <div>
              <label>Unit</label>
              <input value={unit} onChange={(e) => setUnit(e.target.value)} />
            </div>
            <div>
              <label>Price</label>
              <input
                type="number"
                value={price}
                onChange={(e) => setPrice(e.target.value)}
              />
            </div>
            <div>
              <label>Expiry Date</label>
              <input
                type="date"
                value={expiry_date}
                onChange={(e) => setExpiry(e.target.value)}
              />
            </div>
          </div>

          <button className="primaryBtn" onClick={addManual}>
            Add Item
          </button>
        </div>

        <div className="panelCard">
          <h2>Barcode Lookup</h2>
          <p className="panelHint">Scan or enter a barcode to auto-fill product info.</p>

          <div className="actionRow">
            <input
              placeholder="Enter barcode"
              value={barcode}
              onChange={(e) => setBarcode(e.target.value)}
            />
            <button className="primaryBtn" onClick={doBarcodeLookup}>
              Lookup
            </button>
          </div>

          <h2 style={{ marginTop: 24 }}>Voice / NLP Quick Add</h2>
          <p className="panelHint">Example: “I bought 2 liters of milk”</p>

          <div className="actionRow">
            <input
              placeholder='Type something like "1 packet of maggi"'
              value={voiceText}
              onChange={(e) => setVoiceText(e.target.value)}
            />
            <button className="primaryBtn" onClick={doQuickAdd}>
              Quick Add
            </button>
          </div>

          <h2 style={{ marginTop: 24 }}>Receipt OCR</h2>
          <p className="panelHint">Upload a grocery bill to extract items automatically.</p>

          <input
            className="fileInput"
            type="file"
            accept="image/*"
            onChange={(e) => setOcrFile(e.target.files?.[0] || null)}
          />

          <div className="btnRow">
            <button className="primaryBtn" onClick={doOCR}>
              Run OCR
            </button>
            <button className="secondaryBtn" onClick={commitOCR}>
              Save OCR Items
            </button>
          </div>

          {ocrItems.length > 0 && (
            <div className="ocrBox">
              <h4>OCR Items</h4>
              <ul>
                {ocrItems.map((it, idx) => (
                  <li key={idx}>
                    {it.name} — {it.quantity} {it.unit} — ₹{it.price}
                  </li>
                ))}
              </ul>
            </div>
          )}
        </div>
      </div>

      <div className="panelCard">
        <h2>Inventory</h2>
        <div className="inventoryWrap">
          <table className="inventoryTable">
            <thead>
              <tr>
                <th>Item</th>
                <th>Qty</th>
                <th>Expiry</th>
                <th>Status</th>
                <th></th>
              </tr>
            </thead>
            <tbody>
              {items.map((it) => (
                <tr key={it.id}>
                  <td>
                    <div className="itemNameCell">
                      <span>{it.name}</span>
                      <span className="badge">{it.category}</span>
                    </div>
                  </td>
                  <td>
                    {it.quantity} {it.unit}
                  </td>
                  <td>{it.expiry_date || "-"}</td>
                  <td>
                    {it.expiry_date ? (
                      it.at_risk ? (
                        <span className="badge dangerBadge">At Risk</span>
                      ) : (
                        <span className="badge warningBadge">
                          {it.days_to_expiry} day(s)
                        </span>
                      )
                    ) : (
                      <span className="badge neutralBadge">No expiry</span>
                    )}
                  </td>
                  <td>
                    <button className="dangerBtn" onClick={() => del(it.id)}>
                      Delete
                    </button>
                  </td>
                </tr>
              ))}
              {items.length === 0 && (
                <tr>
                  <td colSpan="5" className="emptyRow">
                    No items in pantry yet.
                  </td>
                </tr>
              )}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
}
